export function stringReplaceAll(e,n,t){let i=e.indexOf(n);if(-1===i)return e;const l=n.length;let r=0,c="";do{c+=e.slice(r,i)+n+t,r=i+l,i=e.indexOf(n,r)}while(-1!==i);return c+=e.slice(r),c}export function stringEncaseCRLFWithFirstIndex(e,n,t,i){let l=0,r="";do{const c="\r"===e[i-1];r+=e.slice(l,c?i-1:i)+n+(c?"\r\n":"\n")+t,l=i+1,i=e.indexOf("\n",l)}while(-1!==i);return r+=e.slice(l),r}